import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basic() {
        assertEquals("cdeab", new Solution().rotateStringLeft("abcde", 2));
    }

    @Test
    void kZero() {
        assertEquals("abcde", new Solution().rotateStringLeft("abcde", 0));
    }

    @Test
    void kEqualsLength() {
        // full rotation — same as original
        assertEquals("abcde", new Solution().rotateStringLeft("abcde", 5));
    }

    @Test
    void kGreaterThanLength() {
        // k=7 on length-5 → effective k=2 → same as basic
        assertEquals("cdeab", new Solution().rotateStringLeft("abcde", 7));
    }

    @Test
    void empty() {
        assertEquals("", new Solution().rotateStringLeft("", 3));
    }

    @Test
    void singleChar() {
        assertEquals("a", new Solution().rotateStringLeft("a", 4));
    }

    @Test
    void kOne() {
        assertEquals("bcda", new Solution().rotateStringLeft("abcd", 1));
    }
}
